+    fn pdu_sender_propagates_errors() {
+        let sender = PduSender::new(|_| anyhow::bail!("send failed"));
+        let result = sender.send(DecodedPdu {
+            serial: 0,
+            pdu: Pdu::Pong(Pong {}),
+        });
+        assert!(result.is_err());
